section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/token-organization.json",
  "title": "Token Organization",
  "type": "object",
  "required": [
    "artefact_id",
    "system_id",
    "layers",
    "naming_rules",
    "category_list",
    "exceptions_policy",
    "owners",
    "evidence",
    "review_cadence",
    "status",
    "owner",
    "last_touched",
    "template_version"
  ],
  "properties": {
    "artefact_id": {
      "type": "string",
      "description": "slug + ISO date or UUID",
      "minLength": 1
    },
    "system_id": {
      "type": "string",
      "description": "system_id",
      "minLength": 1
    },
    "layers": {
      "type": "string",
      "description": "layers",
      "minLength": 1
    },
    "naming_rules": {
      "type": "array",
      "description": "naming_rules (array)",
      "minItems": 1
    },
    "category_list": {
      "type": "array",
      "description": "category_list (array)",
      "minItems": 1
    },
    "exceptions_policy": {
      "type": "string",
      "description": "exceptions_policy",
      "minLength": 1
    },
    "owners": {
      "type": "string",
      "description": "owners",
      "minLength": 1
    },
    "evidence": {
      "type": "array",
      "description": "{source, citation} pairs anchoring non-trivial fields",
      "minItems": 1
    },
    "review_cadence": {
      "type": "string",
      "description": "review_cadence",
      "minLength": 1
    },
    "status": {
      "type": "string",
      "description": "draft|ready_for_review|approved|archived",
      "minLength": 1
    },
    "owner": {
      "type": "string",
      "description": "single named owner; generic group terms forbidden",
      "minLength": 1
    },
    "last_touched": {
      "type": "string",
      "description": "ISO-8601 timestamp",
      "format": "date-time"
    },
    "template_version": {
      "type": "string",
      "description": "semver matching methodology frontmatter at write time"
    }
  },
  "additionalProperties": false
}
